----请求初始化数据
function LxGuildScienceHandler:GuildScienceDataReq()
    local proto = LxProtoHelper.CreateProto(LxProtoIds.GuildScienceDataReq)
    SendMessage(LxProtoIds.GuildScienceDataReq, proto)
end

----升级科技
function LxGuildScienceHandler:GuildScienceUpgradeReq(groupId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.GuildScienceUpgradeReq)
    proto.group = groupId
    SendMessage(LxProtoIds.GuildScienceUpgradeReq, proto)
end

----捐献科技
