--- s2c

----军团科技数据,登录下发
function LxGuildScienceHandler:OnGuildScienceDataResp(pb)
    ModuleCenter.GuildScience:SetScienceDataList(pb.scienceObj)
    ModuleCenter.GuildScience:SetRecommendGroupId(pb.recommend)
    ModuleCenter.GuildScience:SetOtherInfo(pb.diamondCount, pb.remainResCount, pb.addResCountTime)
    FireEvent(EventNames.GUILD_SCIENCE_UPDATE)
end

----升级科技后返回的数据
function LxGuildScienceHandler:OnGuildScienceUpgradeResp(pb)
    ShowSysMsg(I18nText(11430))
    ModuleCenter.GuildScience:SetScienceObj(pb.scienceObj)
    FireEvent(EventNames.GUILD_SCIENCE_UPDATE)
end

----捐献科技后返回的数据
function LxGuildScienceHandler:OnGuildScienceDonateResp(pb)
    ShowSysMsg(I18nText(11429))
    if pb.rewardInfo ~= nil then
        FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.GuildScience, pb.rewardInfo)
    end
    ModuleCenter.GuildScience:RefreshObjExp(pb)
    ModuleCenter.GuildScience:SetOtherInfo(pb.diamondCount, pb.remainResCount, pb.addResCountTime)
    FireEvent(EventNames.GUILD_SCIENCE_UPDATE)
end

----科技推荐后返回的数据
function LxGuildScienceHandler:OnGuildScienceRecommendResp(pb)
    ModuleCenter.GuildScience:SetRecommendGroupId(pb.group)
    FireEvent(EventNames.GUILD_SCIENCE_RECOMMEND_UPDATE)
end

return LxGuildScienceHandler